const src = $input.first()?.json ?? {};
let output = src.output ?? src.text ?? src.response ?? src.answer ?? '';

if (typeof output !== 'string') {
  try {
    output = JSON.stringify(output, null, 2);
  } catch (_) {
    output = String(output);
  }
}

return [{
  json: {
    output: output,
    text: output
  }
}];

const items = $input.all();

let requestItems = [];
try {
  requestItems = $items('Build Manual Request');
} catch (_) {}

if (!requestItems.length) {
  try {
    requestItems = $items('Build Chat Request');
  } catch (_) {}
}

return items.map((item, index) => {
  const src = item.json || {};
  const body = src.body && typeof src.body === 'object' ? src.body : {};
  const payload = Object.keys(body).length ? body : src;
  const requestJson = requestItems[index]?.json ?? {};
  const responseText = String(payload.response ?? '');

  return {
    json: {
      mode: requestJson.mode ?? null,
      input_question: requestJson.input_question ?? null,
      llm_request: requestJson.llm_request ?? null,
      llm_response: responseText,
      text: responseText,
      output: responseText,
      model: payload.model ?? requestJson.llm_request?.model ?? null,
      done: payload.done ?? null,
      total_duration: payload.total_duration ?? null
    }
  };
});

const systemPrompt = 'Answer in English and explain your answer clearly.';
const question = ($json.chatInput || '').toString().trim();

return [
  {
    json: {
      mode: 'chat-input',
      input_question: question,
      llm_request: {
        endpoint: 'http://ollama:11434/api/generate',
        model: 'qwen2.5:1.5b',
        stream: false,
        options: {
          temperature: 0.1,
          top_p: 0.9,
          num_predict: 180
        },
        system_prompt: systemPrompt,
        prompt: question
      }
    }
  }
];

const systemPrompt = 'Answer in English and explain your answer clearly.';
const prompt = 'What is 4 + 1?';

return [
  {
    json: {
      mode: 'manual-fixed',
      input_question: prompt,
      llm_request: {
        endpoint: 'http://ollama:11434/api/generate',
        model: 'qwen2.5:1.5b',
        stream: false,
        options: {
          temperature: 0.1,
          top_p: 0.9,
          num_predict: 180
        },
        system_prompt: systemPrompt,
        prompt
      }
    }
  }
];

if (!$env.TEAMCITY_BASE_URL_N8N) throw new Error('Missing env TEAMCITY_BASE_URL_N8N');
if (!$env.TEAMCITY_TOKEN) throw new Error('Missing env TEAMCITY_TOKEN');
if (!$env.TEAMCITY_AI_STRUCTURE_PATH) throw new Error('Missing env TEAMCITY_AI_STRUCTURE_PATH');

return [{
  json: {
    teamcity: {
      baseUrl: $env.TEAMCITY_BASE_URL_N8N,
      token: $env.TEAMCITY_TOKEN
    },
    storage: {
      structurePath: $env.TEAMCITY_AI_STRUCTURE_PATH
    },
    generatedAt: new Date().toISOString()
  }
}];

const ctx = $items('Config')[0].json;
const src = $json.body && typeof $json.body === 'object' ? $json.body : $json;
const buildTypes = Array.isArray(src.buildType) ? src.buildType : [];

const projects = {};

for (const bt of buildTypes) {
  const projectName = bt.projectName || 'Unbekanntes Projekt';

  if (!projects[projectName]) {
    projects[projectName] = {
      projectName,
      projectId: bt.projectId || null,
      buildTypes: [],
      activeBuildTypes: 0,
      pausedBuildTypes: 0
    };
  }

  const item = {
    buildTypeId: bt.id || null,
    buildTypeName: bt.name || null,
    projectName,
    projectId: bt.projectId || null,
    paused: !!bt.paused,
    webUrl: bt.webUrl || null,
    lastSeenAt: new Date().toISOString()
  };

  projects[projectName].buildTypes.push(item);

  if (item.paused) {
    projects[projectName].pausedBuildTypes++;
  } else {
    projects[projectName].activeBuildTypes++;
  }
}

const projectList = Object.values(projects)
  .sort((a, b) => a.projectName.localeCompare(b.projectName));

const overviewText = projectList.map(p => {
  const lines = [];
  lines.push(`Projekt: ${p.projectName}`);
  lines.push(`  BuildTypes aktiv: ${p.activeBuildTypes}`);
  lines.push(`  BuildTypes pausiert: ${p.pausedBuildTypes}`);

  for (const bt of p.buildTypes) {
    lines.push(`  - ${bt.buildTypeName} [${bt.buildTypeId}]${bt.paused ? ' (pausiert)' : ''}`);
  }

  return lines.join('\n');
}).join('\n\n');

return [{
  json: {
    snapshotType: 'teamcity_structure',
    createdAt: new Date().toISOString(),
    totalProjects: projectList.length,
    totalBuildTypes: buildTypes.length,
    projects: projectList,
    overviewText,
    note: 'Projekt -> BuildType. Einzelne Tests kommen erst über Builds und testOccurrences.',
    teamcityBaseUrl: ctx.teamcity.baseUrl,
    storagePath: ctx.storage.structurePath
  }
}];

const snapshot = $json;
const jsonText = JSON.stringify(snapshot, null, 2);

return [{
  json: {
    filePath: snapshot.storagePath || '/data/n8n-exports/teamcity/structure.json',
    snapshotType: snapshot.snapshotType,
    createdAt: snapshot.createdAt,
    totalProjects: snapshot.totalProjects,
    totalBuildTypes: snapshot.totalBuildTypes,
    overviewText: snapshot.overviewText
  },
  binary: {
    data: {
      data: Buffer.from(jsonText, 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName: 'structure.json'
    }
  }
}];

const prepared = $items('Prepare Structure File')[0].json;

return [{
  json: {
    ok: true,
    message: 'TeamCity-Struktur wurde gespeichert.',
    filePath: prepared.filePath,
    totalProjects: prepared.totalProjects,
    totalBuildTypes: prepared.totalBuildTypes,
    overviewText: prepared.overviewText
  }
}];

const input = $json || {};

const rawInput = input.input ?? input.query ?? input.text ?? null;
let parsedInput = null;

if (rawInput && typeof rawInput === 'object') {
  parsedInput = rawInput;
} else if (typeof rawInput === 'string') {
  const trimmed = rawInput.trim();
  if (trimmed.startsWith('{') && trimmed.endsWith('}')) {
    try {
      parsedInput = JSON.parse(trimmed);
    } catch (_) {}
  }
}

const buildTypeId = String(
  input.buildTypeId ??
  input.build_type_id ??
  input.buildType ??
  input.btId ??
  parsedInput?.buildTypeId ??
  parsedInput?.build_type_id ??
  parsedInput?.buildType ??
  parsedInput?.btId ??
  (typeof rawInput === 'string' ? rawInput : '') ??
  ''
).trim();

if (!buildTypeId) {
  throw new Error('Pflichtfeld fehlt: buildTypeId. Beispiel-Input: { "buildTypeId": "demo_alpha_api", "maxTests": 25 }');
}
if (!$env.TEAMCITY_BASE_URL_N8N) throw new Error('Missing env TEAMCITY_BASE_URL_N8N');
if (!$env.TEAMCITY_TOKEN) throw new Error('Missing env TEAMCITY_TOKEN');

const maxTestsRaw = Number(
  input.maxTests ??
  input.max_tests ??
  parsedInput?.maxTests ??
  parsedInput?.max_tests ??
  25
);
const maxTests = Number.isFinite(maxTestsRaw) && maxTestsRaw > 0 ? Math.min(Math.floor(maxTestsRaw), 200) : 25;

return [{
  json: {
    teamcity: {
      baseUrl: $env.TEAMCITY_BASE_URL_N8N,
      token: $env.TEAMCITY_TOKEN
    },
    request: {
      buildTypeId,
      maxTests,
      source: 'executeWorkflowTrigger'
    },
    generatedAt: new Date().toISOString()
  }
}];

const input = $json || {};

const providedBuildTypeId = String(
  input.buildTypeId ??
  input.build_type_id ??
  input.buildType ??
  input.btId ??
  ''
).trim();

const defaultBuildTypeId = String($env.TEAMCITY_DEFAULT_FAILED_BUILD_TYPE_ID ?? '').trim();
const buildTypeId = providedBuildTypeId || defaultBuildTypeId;

if (!buildTypeId) {
  throw new Error('Missing buildTypeId. Set TEAMCITY_DEFAULT_FAILED_BUILD_TYPE_ID in .env or pass buildTypeId manually.');
}
if (!$env.TEAMCITY_BASE_URL_N8N) throw new Error('Missing env TEAMCITY_BASE_URL_N8N');
if (!$env.TEAMCITY_TOKEN) throw new Error('Missing env TEAMCITY_TOKEN');

const maxTestsRaw = Number(input.maxTests ?? input.max_tests ?? 25);
const maxTests = Number.isFinite(maxTestsRaw) && maxTestsRaw > 0 ? Math.min(Math.floor(maxTestsRaw), 200) : 25;

return [{
  json: {
    teamcity: {
      baseUrl: $env.TEAMCITY_BASE_URL_N8N,
      token: $env.TEAMCITY_TOKEN
    },
    request: {
      buildTypeId,
      maxTests,
      source: 'manualTrigger'
    },
    generatedAt: new Date().toISOString()
  }
}];

let ctx = {};

try {
  ctx = $items('Build Query Context (Execute)')[0]?.json || {};
} catch (_) {}

if (!ctx || !Object.keys(ctx).length) {
  try {
    ctx = $items('Build Query Context (Manual)')[0]?.json || {};
  } catch (_) {}
}

const src = $json?.body && typeof $json.body === 'object' ? $json.body : ($json || {});
const builds = Array.isArray(src.build) ? src.build : [];
const failedBuild = builds[0] || null;

return [{
  json: {
    ...ctx,
    build: failedBuild
  }
}];

const ctx = $items('Attach Build Details')[0]?.json || {};
const src = $json?.body && typeof $json.body === 'object' ? $json.body : ($json || {});
const testOccurrences = Array.isArray(src.testOccurrence) ? src.testOccurrence : [];

const failedTests = testOccurrences.map((t) => ({
  name: t.name || null,
  status: t.status || null,
  duration: t.duration || null,
  details: t.details || null,
  runOrder: t.runOrder || null
}));

const snapshot = {
  snapshotType: 'teamcity_failed_tests',
  createdAt: new Date().toISOString(),
  requestSource: ctx.request?.source || null,
  buildTypeId: ctx.request?.buildTypeId || null,
  buildId: ctx.build?.id || null,
  maxTestsRequested: ctx.request?.maxTests || null,
  teamcityBaseUrl: ctx.teamcity?.baseUrl || null,
  build: ctx.build || null,
  totalFailedTests: failedTests.length,
  failedTests,
  message: ctx.build
    ? (failedTests.length ? 'Fehlgeschlagene Tests wurden gefunden.' : 'Build gefunden, aber keine fehlgeschlagenen Tests im Resultat.')
    : 'Kein fehlgeschlagener Build fuer diese BuildType-ID gefunden.'
};

return [{ json: snapshot }];

const snapshot = $json;
if (!$env.TEAMCITY_AI_FAILED_TESTS_PATH) throw new Error('Missing env TEAMCITY_AI_FAILED_TESTS_PATH');

const buildTypeIdForFile = String(snapshot.buildTypeId || 'unknown-buildType').trim();
const hasBuildId = !!snapshot.buildId;
const buildIdForFile = hasBuildId ? String(snapshot.buildId) : '';

let filePath = $env.TEAMCITY_AI_FAILED_TESTS_PATH;
filePath = filePath.replace('{buildTypeId}', buildTypeIdForFile);
filePath = filePath.replace('{buildId}', buildIdForFile);

const fileName = hasBuildId
  ? `failed-tests-${buildTypeIdForFile}-build-${buildIdForFile}.json`
  : `failed-tests-${buildTypeIdForFile}.json`;

const jsonText = JSON.stringify(snapshot, null, 2);

return [{
  json: {
    ...snapshot,
    filePath
  },
  binary: {
    data: {
      data: Buffer.from(jsonText, 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName
    }
  }
}];

const prepared = $items('Prepare Failed Tests File')[0]?.json || {};

return [{
  json: {
    ok: true,
    message: prepared.message || null,
    buildTypeId: prepared.buildTypeId || null,
    buildId: prepared.buildId || null,
    build: prepared.build || null,
    totalFailedTests: prepared.totalFailedTests || 0,
    failedTests: prepared.failedTests || [],
    filePath: prepared.filePath || null
  }
}];
